  <svg viewBox="0 0 700 320" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Heures de marché vs. fenêtre de récupération du cortisol</text>
    <text x="230" y="80" fill="#a1a1aa" font-size="13" font-family="sans-serif">Marché boursier traditionnel (vol. 10&#8211;17%)</text>
